    convert_cmd = "convert -resize 500x500 "

    if ext in ['jpg', 'jpeg']: 
        convert_cmd += "'{0}' '{1}.{2}'"
    else:
        convert_cmd += "'{0}' '{1}'".format(sourcefile, filename, ext)


