    try : 
        os.system('{0}'.format(convert_cmd))
    except Exception as e: 
        log.error("Error on file: {0}".format(e), bucket) 
        return False


    log.info('Converting from WEBP to JPEG') 
    convertwebpcmd = 'convert -resize 500x500 -quality 10 -define webp:lossless=true "{0}.webp" "{0}.{2}"'.format(filename, filename, ext)
    log.info('Performing Convert command: {0}'.format(convertwebpcmd))

