    convertpngcmd = 'convert -resize 500x500 "{0}.{1}" -define webp:method=6 "{0}.webp"'.format(filename, ext)
    log.info('Performing Convert command: {0}'.format(convertpngcmd))

    try : 
        os.system('{0}'.format(convertwebpcmd)) 
    except Exception as e:
        log.error("Error on file: {0}".format(e), bucket) 
        return False


